package org.jsoup.parser;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.jsoup.parser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.jsoup.parser.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;

public class StepDefs {

    private String inputHtml;
    private Document document;
    private String outputHtml;

    @Given("the input HTML is {string}")
    public void the_input_HTML_is(String html) {
        this.inputHtml = html;
    }

    @When("the document is parsed")
    public void the_document_is_parsed() {
        try {
            this.document = Jsoup.parse(inputHtml);
            this.outputHtml = document.html();
        } catch (Exception e) {
            // Capture any exceptions during parsing
            throw new RuntimeException("Error parsing HTML: " + e.getMessage(), e);
        }
    }

    @Then("the output HTML should be {string}")
    public void the_output_HTML_should_be(String expectedHtml) {
        // We need to compare the body content since Jsoup adds <html><head></head><body>... around content
        Document expectedDoc = Jsoup.parse(expectedHtml);
        String expectedBodyHtml = expectedDoc.body().html();
        String actualBodyHtml = document.body().html();

        assertEquals("Parsed HTML does not match expected output", expectedBodyHtml, actualBodyHtml);
    }
}

